const errorData = $input.first().json;

// Extract error details safely
const workflowName = errorData.workflow?.name || 'Unknown Workflow';
const workflowId   = errorData.workflow?.id   || 'N/A';
const executionId  = errorData.execution?.id  || 'N/A';
const lastNode     = errorData.execution?.lastNodeExecuted || 'Unknown Node';
const errorMessage = errorData.execution?.error?.message  || 'No error message available';
const errorTime    = new Date().toLocaleString('en-US', {
  timeZone: 'Asia/Dubai',
  year: 'numeric', month: 'long', day: 'numeric',
  hour: '2-digit', minute: '2-digit', second: '2-digit'
});

// ─────────────────────────────────────────────────────────────
// 🎨 Workflow themes (color + icon per workflow)
// ─────────────────────────────────────────────────────────────
const workflowThemes = {
  'QB (Receive Payment)':    { color: '#27ae60', icon: '💰', label: 'Receive Payment'    },
  'QB Invoice':              { color: '#2980b9', icon: '🧾', label: 'Invoice'            },
  'QB (All)':                { color: '#8e44ad', icon: '📦', label: 'All Records'        },
  'QB (Purchase Order)':     { color: '#e67e22', icon: '🛒', label: 'Purchase Order'     },
  'QB (Quotation/Estimate)': { color: '#16a085', icon: '📋', label: 'Quotation/Estimate' }
};

const theme = workflowThemes[workflowName] || { color: '#e74c3c', icon: '⚙️', label: workflowName };

// ─────────────────────────────────────────────────────────────
// 🚨 Severity Logic
// - WARNING  → shown for ALL node failures by default (🟡)
// - CRITICAL → only if the error message contains specific keywords
// ─────────────────────────────────────────────────────────────
const criticalKeywords = ['timeout', 'connection refused', 'authentication', 'unauthorized', '500', 'ECONNREFUSED', 'Cannot read', 'null', 'undefined'];
const isCritical = criticalKeywords.some(k => errorMessage.toLowerCase().includes(k.toLowerCase()));

const severity      = isCritical ? '🔴 CRITICAL' : '🟡 WARNING';
const severityColor = isCritical ? '#e74c3c'      : '#f39c12';
const severityBg    = isCritical ? '#fff5f5'      : '#fffbf0';
const severityBorder= isCritical ? '#e74c3c'      : '#f39c12';

// ─────────────────────────────────────────────────────────────
// 📧 HTML Email Body
// ─────────────────────────────────────────────────────────────
const htmlBody = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; background: #f4f4f4; margin: 0; padding: 20px; }
    .container { background: white; border-radius: 8px; padding: 30px; max-width: 650px; margin: auto; border-top: 5px solid ${theme.color}; }
    .header { text-align: center; margin-bottom: 25px; }
    .header h1 { color: ${theme.color}; font-size: 24px; margin: 0; }
    .header p { color: #666; margin: 5px 0 0; font-size: 14px; }
    .severity-badge { display: inline-block; background: ${severityColor}; color: white; padding: 4px 12px; border-radius: 20px; font-size: 13px; font-weight: bold; margin-bottom: 20px; }
    .info-table { width: 100%; border-collapse: collapse; margin: 20px 0; }
    .info-table tr { border-bottom: 1px solid #eee; }
    .info-table td { padding: 10px 8px; font-size: 14px; }
    .info-table td:first-child { font-weight: bold; color: #555; width: 38%; }
    .info-table td:last-child { color: #333; }
    .error-box { background: ${isCritical ? '#fff5f5' : '#fffbf0'}; border: 1px solid ${isCritical ? '#fcc' : '#ffe0a0'}; border-left: 4px solid ${isCritical ? '#e74c3c' : '#f39c12'}; border-radius: 4px; padding: 15px; margin: 20px 0; }
    .error-box h3 { color: ${isCritical ? '#c0392b' : '#d68910'}; margin: 0 0 8px; font-size: 14px; }
    .error-box pre { margin: 0; color: #333; font-size: 13px; white-space: pre-wrap; word-break: break-word; }
    .btn { display: inline-block; background: #2c3e50; color: white; padding: 12px 24px; border-radius: 5px; text-decoration: none; font-size: 14px; font-weight: bold; margin-top: 15px; }
    .footer { margin-top: 30px; padding-top: 15px; border-top: 1px solid #eee; font-size: 12px; color: #999; text-align: center; }
    .node-highlight { background: #ffeaa7; padding: 2px 8px; border-radius: 3px; font-weight: bold; color: #2d3436; }
    .wf-strip { background: ${theme.color}15; border-left: 4px solid ${theme.color}; padding: 10px 15px; border-radius: 4px; margin-bottom: 20px; font-size: 14px; color: #333; }
  </style>
</head>
<body>
  <div class="container">

    <div class="header">
      <h1>${theme.icon} Workflow Error Alert</h1>
      <p>An error occurred in your n8n automation</p>
    </div>

    <div style="text-align:center">
      <span class="severity-badge">${severity}</span>
    </div>

    <div class="wf-strip">
      ${isCritical ? '🚨' : '⚠️'} The <strong>${workflowName}</strong> workflow failed at node <span class="node-highlight">${lastNode}</span>.
      ${isCritical ? 'Immediate attention required.' : 'Please review when possible.'}
    </div>

    <table class="info-table">
      <tr>
        <td>🏷️ Workflow Name</td>
        <td><strong>${workflowName}</strong></td>
      </tr>
      <tr>
        <td>🔖 Workflow ID</td>
        <td>${workflowId}</td>
      </tr>
      <tr>
        <td>🆔 Execution ID</td>
        <td>${executionId}</td>
      </tr>
      <tr>
        <td>💥 Failed Node</td>
        <td><span class="node-highlight">${lastNode}</span></td>
      </tr>
      <tr>
        <td>🕐 Error Time </td>
        <td>${errorTime}</td>
      </tr>
    </table>

    <div class="error-box">
      <h3>${isCritical ? '❌' : '⚠️'} Error Message</h3>
      <pre>${errorMessage}</pre>
    </div>

    <p style="font-size:14px; color:#555;">Please check the execution log in n8n for full details and fix the issue as soon as possible.</p>

    <div style="text-align:center">
      <a class="btn" href="https://n8n.jlsyachts.com/workflow/${workflowId}/executions/${executionId}" target="_blank">🔍 View Execution in n8n</a>
    </div>

    <div class="footer">
      This is an automated error alert from your n8n workflow system.<br/>
      Workflow: ${workflowName} | Time: ${errorTime}
    </div>

  </div>
</body>
</html>
`;

// ─────────────────────────────────────────────────────────────
// 📄 Plain text fallback
// ─────────────────────────────────────────────────────────────
const textBody = `
WORKFLOW ERROR ALERT
====================
Severity     : ${severity}
Workflow     : ${workflowName}
Workflow ID  : ${workflowId}
Execution ID : ${executionId}
Failed Node  : ${lastNode}
Error Time   : ${errorTime}

ERROR MESSAGE:
${errorMessage}

View in n8n:
https://n8n.jlsyachts.com/workflow/${workflowId}/executions/${executionId}
`;

return [{
  json: {
    workflowName,
    workflowId,
    executionId,
    lastNode,
    errorMessage,
    errorTime,
    severity,
    isCritical,
    htmlBody,
    textBody,
    emailSubject: `${severity} | ${workflowName} | Node: ${lastNode} Failed`
  }
}];

